    const n = nums.length;
    const dp = new Array(n + 1).fill(null).map(() => new Array(n * 2 + 1).fill(-1));

    function gcd(x, y) {
        if (y === 0) return x;
        return gcd(y, x % y);
    }

    function dfs(i, j) {
        if (i > n) return 0;
        if (dp[i][j] !== -1) return dp[i][j];
        let ans = 0;
        for (let k = j + 1; k < n * 2; k++) {
            ans = Math.max(ans, dfs(i + 1, k) + i * gcd(nums[j], nums[k]));
        }
        return dp[i][j] = ans;
    }

    return dfs(1, 0);
}
